INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('fire-eq-eng-moex-00011', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準規定，有關滅火器核算其最低滅火效能值規定，下列敘述 何者正確？', '["公共危險物品處理場所之建築物外牆為非防火構造者，總樓地板面積每 50 平方公尺（含 未滿）有一滅火效能值", "甲類場所各層樓地板面積每50平方公尺（含未滿）有一滅火效能值", "公共危險物品儲存場所之建築物，外牆為防火構造者，總樓地板面積每100平方公尺（含 未滿）有一滅火效能值", "位於公共危險物品製造場所之室外具有連帶使用關係之附屬設施，以該設施水平最大面積 為其樓地板面積，每150平方公尺（含未滿）有一滅火效能值"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00012', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '某室內停車空間，第一層樓地板面積為600平方公尺，依各類場所消防安全設備設置標準規 定，應就水霧、泡沫、乾粉、二氧化碳滅火設備等選擇設置之，但外牆開口面積（常時開放 部分）達多少平方公尺時，滅火設備得採移動式設置？', '["60", "90", "120", "180"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00013', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準相關規定，下列敘述何者正確？', '["建築物之各層樓在判定是否為無開口樓層之標準是相同的", "易燃性液體物質之閃火點超過攝氏60度之作業場所是屬於高度危險工作場所", "圖書館與紀念館是同一目用途的場所", "各類場所符合建築技術規則以無開口且具半小時以上防火時效之牆壁、樓地板區劃分隔 者，適用各類場所消防安全設備設置標準各編規定，視為另一場所"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00014', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體製造儲存處理場所設置標準暨安全管理辦法規定，某公共 危險物品室內儲存場所規劃儲存達管制量200倍以上易燃液體，經檢討其四周保留空地寬度 依法需10公尺，倘該場所臨近河川，其保留空地面臨河川部分，得縮減為幾公尺？', '["0", "1", "3", "5"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00015', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '有關火警受信總機認可基準規定，下列敘述何者錯誤？', '["接受由探測器或火警發信機所發出之信號，或經中繼器或介面器轉換成警報信號，告知有 關人員火警發生之設備，附有防災連動控制之設備者應同時啟動之者，係為R型受信總機", "反覆試驗係指將受信總機之任一回路以額定電壓施予10000次之火警動作試驗後，對受信 總機本身之構造及功能不得有異狀發生", "新技術開發之火警受信總機，依形狀、構造、材質及性能判定，如符合火警受信總機認可 基準規定及同等以上性能，並經中央消防主管機關認定者，得不受火警受信總機認可基準 之規範", "辦理型式認可作業時，僅提供型式試驗之樣品1個即可"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00016', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依滅火器認可基準規定，有關住宅用滅火器之型式及構造，下列敘述何者正確？', '["應為蓄壓式滅火器，且不具更換或充填滅火藥劑之構造", "應為加壓式滅火器，且不具更換或充填滅火藥劑之構造", "應為蓄壓式滅火器，且具更換或充填滅火藥劑之構造", "應為加壓式滅火器，且具更換或充填滅火藥劑之構造"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00017', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防機具器材及設備認可實施辦法規定，下列敘述何者錯誤？', '["消防機具器材及設備之型式認可基準係由內政部公告", "取得個別認可之消防機具器材及設備，登錄機構應予編號登錄，並將各項認可資訊登載於 網站，隨時更新", "申請個別認可，應檢附文件向登錄機構辦理，而型式認可書影本是其中一項", "申請個別認可時，得向登錄機構申請預先領用標示"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00018', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依滅火器藥劑更換及充填作業規定，廠商更換滅火藥劑並完成檢修或更新後應於滅火器加裝 檢修環，有關檢修環相關規定，下列敘述何者錯誤？', '["應於滅火器瓶頸加裝檢修環", "檢修環材質以一體成型之硬質無縫塑膠、壓克力或鐵環製作", "檢修環內徑不得大於滅火器瓶口1mm", "檢修環顏色以紅色、黃色交替更換"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00019', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依滅火器藥劑更換及充填作業規定，下列敘述何者錯誤？', '["充填滅火藥劑之容器及鋼瓶，應符合滅火器認可基準之氣密試驗", "重新充填滅火藥劑後之滅火器，於充填完成時其噴射性能須能噴射所充填滅火劑容量或重 量80%以上之量，其使用期限內噴射性能須能噴射所充填滅火劑容量或重量90%以上之量", "泡沫滅火藥劑因經較長時間後會產生變化，應依滅火器銘板上所標示之時間或依製造商之 使用規範，定期加以更換。其餘類型滅火器之滅火藥劑若無固化結塊、異物、沉澱物、變 色、污濁或異臭者等情形，滅火藥劑可繼續使用", "新增充填之滅火藥劑應為經內政部認可之產品，汰換之滅火藥劑未經回收處理重新辦理認 可，取得個別認可標示，不得重複使用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00020', 'fire-eq-eng', 'fire-eq-eng-moex-109-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依水道連結型自動撒水設備設置基準，有關水道連結型自動撒水設備設置規定，下列敘述何 者錯誤？', '["水源容量：以4顆水道連結型撒水頭，持續放水20分鐘以上計算之", "設置水道連結型自動撒水設備之長期照顧服務機構等場所，其洗手間、浴室或廁所免設水 道連結型撒水頭", "水道連結型撒水頭放水量應在每分鐘30公升以上", "水道連結型撒水頭最末端放水壓力應在每平方公分0.5公斤以上或0.05百萬帕斯卡（MPa） 以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:20+00:00", "source_pdf_sha1": "e0347a5cd0a7", "answer_pdf_sha1": "e6424943ad88", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
